#!/usr/bin/env node

/**
 * codemod-docs-to-requirements.js — Phase 1 final-B.
 *
 * Replaces:
 *   docs/05-features                  →  requirements/05-features
 *   docs/03-requirement-standards     →  requirements/_standards
 *
 * Across the framework + product code surface. Skips:
 *   - History/snapshots: events.jsonl, memory/, dispatch-backups, retros, runtime/, .warpos-backup, dreams
 *   - Worktrees: .worktrees/
 *   - Plan docs that describe the rename itself: BACKLOG.md, CHANGELOG.md
 *   - Generated artifacts that get rebuilt anyway: framework-manifest.json (regenerated by 1C generator)
 *   - Tooling: node_modules, .git, .next, build, out, coverage
 *   - The codemod itself + the path-lint registry/rules
 *
 * Run:
 *   node scripts/warpos/codemod-docs-to-requirements.js              # dry-run, report per-file
 *   node scripts/warpos/codemod-docs-to-requirements.js --apply      # write changes
 */

const fs = require("fs");
const path = require("path");

const ROOT = path.resolve(__dirname, "..", "..");
const APPLY = process.argv.includes("--apply");

const REPLACEMENTS = [
  { from: "docs/05-features", to: "requirements/05-features" },
  { from: "docs/03-requirement-standards", to: "requirements/_standards" },
];

const ALLOWED_EXT = new Set([
  ".md",
  ".js",
  ".ts",
  ".tsx",
  ".json",
  ".jsonl",
  ".sh",
  ".txt",
  ".mjs",
  ".cjs",
]);

const SKIP_DIR_NAMES = new Set([
  "node_modules",
  ".git",
  ".next",
  "out",
  "build",
  "coverage",
  ".worktrees",
  ".warpos-backup",
  "backups",
  ".tmp-triage",
]);

const SKIP_PATH_SUBSTRINGS = [
  ".claude/runtime/",
  ".claude/project/events/",
  ".claude/project/memory/",
  ".claude/dreams/",
  ".claude/agents/.system/dispatch-backups/",
  ".claude/agents/02-oneshot/.system/retros/",
  ".claude/agents/02-oneshot/.system/store.json",
  ".claude/.session-checkpoint",
  ".claude/.last-checkpoint",
  ".claude/.agent-result-hashes",
  // The backlog + the rename catalog speak about the move; leave them.
  "BACKLOG.md",
  "CHANGELOG.md",
  "CHANGELOG-test-system.md",
  // Generated/registry artifacts (rebuilt or already correct):
  ".claude/framework-manifest.json",
  ".claude/framework-installed.json",
  "scripts/path-lint.rules.generated.json",
  "scripts/hooks/lib/paths.generated.js",
  // The codemod itself + path-lint script with the rule embedded:
  "scripts/warpos/codemod-docs-to-requirements.js",
  "scripts/path-lint.js",
  "warpos/paths.registry.json",
];

function isSkipped(rel) {
  for (const s of SKIP_PATH_SUBSTRINGS) if (rel.includes(s)) return true;
  return false;
}

function walk(dir, results = []) {
  for (const entry of fs.readdirSync(dir, { withFileTypes: true })) {
    if (SKIP_DIR_NAMES.has(entry.name)) continue;
    const full = path.join(dir, entry.name);
    const rel = path.relative(ROOT, full).replace(/\\/g, "/");
    if (entry.isDirectory()) {
      walk(full, results);
      continue;
    }
    if (entry.isFile()) {
      const ext = path.extname(entry.name).toLowerCase();
      if (!ALLOWED_EXT.has(ext)) continue;
      if (isSkipped(rel)) continue;
      results.push(full);
    }
  }
  return results;
}

function applyReplacements(content) {
  let out = content;
  let totalHits = 0;
  for (const { from, to } of REPLACEMENTS) {
    let count = 0;
    const re = new RegExp(from.replace(/[.*+?^${}()|[\]\\]/g, "\\$&"), "g");
    out = out.replace(re, () => {
      count++;
      return to;
    });
    totalHits += count;
  }
  return { out, totalHits };
}

const files = walk(ROOT);
let totalReplacements = 0;
let touchedFiles = 0;
const report = [];

for (const file of files) {
  let content;
  try {
    content = fs.readFileSync(file, "utf8");
  } catch {
    continue;
  }
  const { out, totalHits } = applyReplacements(content);
  if (totalHits === 0) continue;
  const rel = path.relative(ROOT, file).replace(/\\/g, "/");
  report.push({ rel, hits: totalHits });
  totalReplacements += totalHits;
  touchedFiles++;
  if (APPLY && out !== content) fs.writeFileSync(file, out);
}

console.log(
  `\ncodemod-docs-to-requirements (mode: ${APPLY ? "apply" : "dry-run"})`,
);
console.log(`  Files scanned: ${files.length}`);
console.log(`  Files with hits: ${touchedFiles}`);
console.log(`  Total replacements: ${totalReplacements}\n`);
const top = report.sort((a, b) => b.hits - a.hits).slice(0, 30);
for (const r of top) console.log(`    ${String(r.hits).padStart(3)}  ${r.rel}`);
if (report.length > top.length) {
  console.log(`    … and ${report.length - top.length} more files`);
}
console.log(
  APPLY
    ? `\nApplied. Verify with: git diff --stat`
    : `\nDry-run only. Re-run with --apply to write changes.`,
);
